class Solution:
    def rotateRight(self, head, k):
        vals = []
        node = head
        while node:
            vals.append(node.val)
            node = node.next
        n = len(vals)
        if n == 0:
            return None
        k %= n
        rotated = vals[-k:] + vals[:-k] if k else vals
        out = None
        for v in reversed(rotated):
            out = ListNode(v, out)
        return out

