var rotateRight = function(head, k) {
    if (!head || !head.next) return head;
    let n = 1;
    let tail = head;
    while (tail.next) {
        tail = tail.next;
        n += 1;
    }
    k %= n;
    if (k === 0) return head;
    tail.next = head;
    let steps = n - k;
    let newTail = head;
    for (let i = 0; i < steps - 1; i++) {
        newTail = newTail.next;
    }
    const newHead = newTail.next;
    newTail.next = null;
    return newHead;
};
